(function(){const menuToggle=document.getElementById('menuToggle'),sidebar=document.getElementById('sidebar');function toggleSidebar(open){const isOpen="boolean"==typeof open?open:!sidebar.classList.contains('active');sidebar.classList.toggle('active',isOpen);sidebar.setAttribute('aria-hidden',String(!isOpen));menuToggle.setAttribute('aria-expanded',String(isOpen));menuToggle.setAttribute('aria-label',isOpen?'Close navigation':'Open navigation')}menuToggle.addEventListener('click',function(e){e.stopPropagation();toggleSidebar()});menuToggle.addEventListener('keydown',function(e){if('Enter'===e.key||' '===e.key){e.preventDefault();toggleSidebar()}});document.addEventListener('keydown',function(e){if('Escape'===e.key&&sidebar.classList.contains('active')&&window.innerWidth<=968){toggleSidebar(false);menuToggle.focus()}});document.addEventListener('click',function(e){if(window.innerWidth<=968&&sidebar.classList.contains('active')){if(!sidebar.contains(e.target)&&e.target!==menuToggle)toggleSidebar(false)}});let resizeTimer;window.addEventListener('resize',function(){clearTimeout(resizeTimer);resizeTimer=setTimeout(function(){if(window.innerWidth>968){sidebar.classList.remove('active');sidebar.setAttribute('aria-hidden','false');menuToggle.setAttribute('aria-expanded','false')}},150)})})();